import{_ as a,o as s,c as t,ae as l}from"./chunks/framework.BEtfQoF7.js";const u=JSON.parse('{"title":"Claude Code 개요","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md","lastUpdated":1776205703000}'),i={name:"overview.md"};function d(o,e,c,p,r,h){return s(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="claude-code-개요" tabindex="-1">Claude Code 개요 <a class="header-anchor" href="#claude-code-개요" aria-label="Permalink to &quot;Claude Code 개요&quot;">​</a></h1><blockquote><p>Claude Code는 코드베이스를 읽고, 파일을 편집하고, 명령을 실행하고, 개발 도구와 통합되는 에이전틱 코딩 도구입니다. 터미널, IDE, 데스크톱 앱, 브라우저에서 사용할 수 있습니다.</p></blockquote><p>Claude Code는 기능 구축, 버그 수정, 개발 작업 자동화를 돕는 AI 기반 코딩 어시스턴트입니다. 전체 코드베이스를 이해하고 여러 파일과 도구에 걸쳐 작업을 수행할 수 있습니다.</p><h2 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h2><p>환경을 선택하여 시작하세요. 대부분의 환경에서는 <a href="https://claude.com/pricing?utm_source=claude_code&amp;utm_medium=docs&amp;utm_content=overview_pricing" target="_blank" rel="noreferrer">Claude 구독</a> 또는 <a href="https://console.anthropic.com/" target="_blank" rel="noreferrer">Anthropic Console</a> 계정이 필요합니다. Terminal CLI와 VS Code는 <a href="/claude-code-docs-ko/third-party-integrations.html">타사 제공업체</a>도 지원합니다.</p><p>::: tabs</p><p>== Terminal</p><p>터미널에서 직접 Claude Code로 작업하기 위한 완전한 기능의 CLI입니다. 파일 편집, 명령 실행, 전체 프로젝트 관리를 커맨드 라인에서 수행합니다.</p><p>Claude Code를 설치하려면 다음 방법 중 하나를 사용하세요:</p><p><strong>네이티브 설치 (권장)</strong></p><p><strong>macOS, Linux, WSL:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://claude.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell:</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">claude.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD:</strong></p><div class="language-batch vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">batch</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl -fsSL https://claude.ai/install.cmd -o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> del</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd</span></span></code></pre></div><p><code>The token &#39;&amp;&amp;&#39; is not a valid statement separator</code>가 표시되면 CMD가 아닌 PowerShell에 있는 것입니다. 위의 PowerShell 명령을 대신 사용하세요. 프롬프트가 <code>PS C:\\</code>로 표시되면 PowerShell에 있는 것입니다.</p><p><strong>네이티브 Windows 설정에는 <a href="https://git-scm.com/downloads/win" target="_blank" rel="noreferrer">Git for Windows</a>가 필요합니다.</strong> 없는 경우 먼저 설치하세요. WSL 설정에서는 필요하지 않습니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>네이티브 설치는 최신 버전을 유지하기 위해 백그라운드에서 자동 업데이트됩니다.</p></div><p><strong>Homebrew</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-code</span></span></code></pre></div><p>Homebrew는 두 가지 cask를 제공합니다. <code>claude-code</code>는 안정 릴리스 채널을 추적하며 일반적으로 약 일주일 뒤처지고 주요 회귀가 있는 릴리스를 건너뜁니다. <code>claude-code@latest</code>는 최신 채널을 추적하며 새 버전이 출시되는 즉시 수신합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Homebrew 설치는 자동 업데이트되지 않습니다. 최신 기능과 보안 수정을 받으려면 설치한 cask에 따라 <code>brew upgrade claude-code</code> 또는 <code>brew upgrade claude-code@latest</code>를 실행하세요.</p></div><p><strong>WinGet</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install Anthropic.ClaudeCode</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>WinGet 설치는 자동 업데이트되지 않습니다. 최신 기능과 보안 수정을 받으려면 주기적으로 <code>winget upgrade Anthropic.ClaudeCode</code>를 실행하세요.</p></div><p>그런 다음 아무 프로젝트에서 Claude Code를 시작하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your-project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>처음 사용 시 로그인하라는 메시지가 표시됩니다. 끝입니다! <a href="/claude-code-docs-ko/quickstart.html">빠른 시작으로 계속하기 →</a></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>설치 옵션, 수동 업데이트 또는 제거 지침은 <a href="/claude-code-docs-ko/setup.html">고급 설정</a>을 참조하세요. 문제가 발생하면 <a href="/claude-code-docs-ko/troubleshooting.html">문제 해결</a>을 방문하세요.</p></div><p>== VS Code</p><p>VS Code 확장은 인라인 diff, @-멘션, 계획 리뷰, 대화 기록을 편집기에서 직접 제공합니다.</p><ul><li><a href="vscode:extension/anthropic.claude-code" target="_blank" rel="noreferrer">VS Code용 설치</a></li><li><a href="cursor:extension/anthropic.claude-code" target="_blank" rel="noreferrer">Cursor용 설치</a></li></ul><p>또는 확장 뷰(<code>Cmd+Shift+X</code> (Mac), <code>Ctrl+Shift+X</code> (Windows/Linux))에서 &quot;Claude Code&quot;를 검색하세요. 설치 후 명령 팔레트(<code>Cmd+Shift+P</code> / <code>Ctrl+Shift+P</code>)를 열고 &quot;Claude Code&quot;를 입력한 후 <strong>Open in New Tab</strong>을 선택하세요.</p><p><a href="/claude-code-docs-ko/vs-code.html#get-started">VS Code 시작하기 →</a></p><p>== 데스크톱 앱</p><p>IDE나 터미널 밖에서 Claude Code를 실행하기 위한 독립 실행형 앱입니다. diff를 시각적으로 검토하고, 여러 세션을 나란히 실행하고, 반복 작업을 예약하고, 클라우드 세션을 시작하세요.</p><p>다운로드 및 설치:</p><ul><li><a href="https://claude.ai/api/desktop/darwin/universal/dmg/latest/redirect?utm_source=claude_code&amp;utm_medium=docs" target="_blank" rel="noreferrer">macOS</a> (Intel 및 Apple Silicon)</li><li><a href="https://claude.ai/api/desktop/win32/x64/setup/latest/redirect?utm_source=claude_code&amp;utm_medium=docs" target="_blank" rel="noreferrer">Windows</a> (x64)</li><li><a href="https://claude.ai/api/desktop/win32/arm64/setup/latest/redirect?utm_source=claude_code&amp;utm_medium=docs" target="_blank" rel="noreferrer">Windows ARM64</a></li></ul><p>설치 후 Claude를 실행하고 로그인한 다음 <strong>Code</strong> 탭을 클릭하여 코딩을 시작하세요. <a href="https://claude.com/pricing?utm_source=claude_code&amp;utm_medium=docs&amp;utm_content=overview_desktop_pricing" target="_blank" rel="noreferrer">유료 구독</a>이 필요합니다.</p><p><a href="/claude-code-docs-ko/desktop-quickstart.html">데스크톱 앱에 대해 자세히 알아보기 →</a></p><p>== Web</p><p>로컬 설정 없이 브라우저에서 Claude Code를 실행합니다. 장기 실행 작업을 시작하고 완료되면 확인하거나, 로컬에 없는 리포지토리에서 작업하거나, 여러 작업을 병렬로 실행하세요. 데스크톱 브라우저와 Claude iOS 앱에서 사용할 수 있습니다.</p><p><a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a>에서 코딩을 시작하세요.</p><p><a href="/claude-code-docs-ko/web-quickstart.html">웹에서 시작하기 →</a></p><p>== JetBrains</p><p>대화형 diff 보기 및 선택 컨텍스트 공유 기능을 갖춘 IntelliJ IDEA, PyCharm, WebStorm 및 기타 JetBrains IDE용 플러그인입니다.</p><p>JetBrains Marketplace에서 <a href="https://plugins.jetbrains.com/plugin/27310-claude-code-beta-" target="_blank" rel="noreferrer">Claude Code 플러그인</a>을 설치하고 IDE를 재시작하세요.</p><p><a href="/claude-code-docs-ko/jetbrains.html">JetBrains 시작하기 →</a></p><p>:::</p><h2 id="할-수-있는-것들" tabindex="-1">할 수 있는 것들 <a class="header-anchor" href="#할-수-있는-것들" aria-label="Permalink to &quot;할 수 있는 것들&quot;">​</a></h2><p>Claude Code를 사용할 수 있는 몇 가지 방법은 다음과 같습니다:</p><details class="details custom-block"><summary>미루고 있던 작업 자동화</summary><p>Claude Code는 하루를 잡아먹는 지루한 작업을 처리합니다: 테스트되지 않은 코드에 대한 테스트 작성, 프로젝트 전체의 lint 오류 수정, 병합 충돌 해결, 의존성 업데이트, 릴리스 노트 작성.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;write tests for the auth module, run them, and fix any failures&quot;</span></span></code></pre></div></details><details class="details custom-block"><summary>기능 구축 및 버그 수정</summary><p>원하는 것을 자연어로 설명하세요. Claude Code가 접근 방식을 계획하고, 여러 파일에 걸쳐 코드를 작성하고, 작동을 검증합니다.</p><p>버그의 경우 오류 메시지를 붙여넣거나 증상을 설명하세요. Claude Code가 코드베이스를 통해 문제를 추적하고, 근본 원인을 파악하고, 수정을 구현합니다. 더 많은 예시는 <a href="/claude-code-docs-ko/common-workflows.html">일반 워크플로우</a>를 참조하세요.</p></details><details class="details custom-block"><summary>커밋 및 풀 리퀘스트 생성</summary><p>Claude Code는 git과 직접 작업합니다. 변경 사항을 스테이징하고, 커밋 메시지를 작성하고, 브랜치를 생성하고, 풀 리퀘스트를 엽니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;commit my changes with a descriptive message&quot;</span></span></code></pre></div><p>CI에서는 <a href="/claude-code-docs-ko/github-actions.html">GitHub Actions</a> 또는 <a href="/claude-code-docs-ko/gitlab-ci-cd.html">GitLab CI/CD</a>로 코드 리뷰 및 이슈 분류를 자동화할 수 있습니다.</p></details><details class="details custom-block"><summary>MCP로 도구 연결</summary><p><a href="/claude-code-docs-ko/mcp.html">Model Context Protocol (MCP)</a>은 AI 도구를 외부 데이터 소스에 연결하기 위한 개방형 표준입니다. MCP를 사용하면 Claude Code가 Google Drive의 디자인 문서를 읽고, Jira의 티켓을 업데이트하고, Slack에서 데이터를 가져오거나, 자체 커스텀 도구를 사용할 수 있습니다.</p></details><details class="details custom-block"><summary>지침, 스킬, 훅으로 커스터마이즈</summary><p><a href="/claude-code-docs-ko/memory.html"><code>CLAUDE.md</code></a>는 프로젝트 루트에 추가하는 마크다운 파일로, Claude Code가 매 세션 시작 시 읽습니다. 코딩 표준, 아키텍처 결정, 선호하는 라이브러리, 리뷰 체크리스트를 설정하는 데 사용합니다. Claude는 작업하면서 <a href="/claude-code-docs-ko/memory.html#auto-memory">자동 메모리</a>도 구축하여, 빌드 명령과 디버깅 인사이트 같은 학습 내용을 아무것도 작성하지 않아도 세션 간에 저장합니다.</p><p><a href="/claude-code-docs-ko/skills.html">사용자 정의 명령</a>을 만들어 <code>/review-pr</code>이나 <code>/deploy-staging</code>과 같은 반복 가능한 워크플로우를 팀과 공유할 수 있습니다.</p><p><a href="/claude-code-docs-ko/hooks.html">훅</a>을 사용하면 Claude Code 동작 전후에 셸 명령을 실행할 수 있습니다. 예를 들어 파일 편집 후 자동 포맷팅이나 커밋 전 lint 실행 등이 있습니다.</p></details><details class="details custom-block"><summary>에이전트 팀 실행 및 사용자 정의 에이전트 구축</summary><p>작업의 다른 부분에서 동시에 작업하는 <a href="/claude-code-docs-ko/sub-agents.html">여러 Claude Code 에이전트</a>를 생성합니다. 리드 에이전트가 작업을 조율하고, 하위 작업을 할당하고, 결과를 병합합니다.</p><p>완전한 커스텀 워크플로우의 경우, <a href="/claude-code-docs-ko/agent-sdk/overview.html">Agent SDK</a>를 사용하면 오케스트레이션, 도구 접근, 권한을 완전히 제어하면서 Claude Code의 도구와 기능으로 구동되는 자체 에이전트를 구축할 수 있습니다.</p></details><details class="details custom-block"><summary>CLI로 파이프, 스크립트, 자동화</summary><p>Claude Code는 조합 가능하며 Unix 철학을 따릅니다. 로그를 파이프하거나, CI에서 실행하거나, 다른 도구와 체이닝하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 최근 로그 출력 분석</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -200</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Slack me if you see any anomalies&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># CI에서 번역 자동화</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;translate new strings into French and raise a PR for review&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 파일 전체에 대한 대량 작업</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name-only</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;review these changed files for security issues&quot;</span></span></code></pre></div><p>전체 명령 및 플래그 세트는 <a href="/claude-code-docs-ko/cli-reference.html">CLI 참조</a>를 확인하세요.</p></details><details class="details custom-block"><summary>반복 작업 예약</summary><p>Claude를 일정에 따라 실행하여 반복되는 작업을 자동화하세요: 아침 PR 리뷰, 야간 CI 실패 분석, 주간 의존성 감사, PR 병합 후 문서 동기화.</p><ul><li><a href="/claude-code-docs-ko/web-scheduled-tasks.html">클라우드 예약 작업</a>은 Anthropic 관리 인프라에서 실행되므로 컴퓨터가 꺼져 있어도 계속 실행됩니다. 웹, 데스크톱 앱에서 생성하거나 CLI에서 <code>/schedule</code>을 실행하여 생성합니다.</li><li><a href="/claude-code-docs-ko/desktop-scheduled-tasks.html">데스크톱 예약 작업</a>은 로컬 파일과 도구에 직접 접근하여 사용자의 컴퓨터에서 실행됩니다.</li><li><a href="/claude-code-docs-ko/scheduled-tasks.html"><code>/loop</code></a>는 빠른 폴링을 위해 CLI 세션 내에서 프롬프트를 반복합니다.</li></ul></details><details class="details custom-block"><summary>어디서든 작업</summary><p>세션은 단일 환경에 묶여 있지 않습니다. 컨텍스트가 변경되면 환경 간에 작업을 이동하세요:</p><ul><li>자리를 비우고 휴대폰이나 아무 브라우저에서 <a href="/claude-code-docs-ko/remote-control.html">Remote Control</a>로 계속 작업</li><li>휴대폰에서 <a href="/claude-code-docs-ko/desktop.html#sessions-from-dispatch">Dispatch</a>에 작업을 메시지하고 생성된 데스크톱 세션을 열기</li><li><a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹</a>이나 <a href="https://apps.apple.com/app/claude-by-anthropic/id6473753684" target="_blank" rel="noreferrer">iOS 앱</a>에서 장기 실행 작업을 시작한 다음 <code>claude --teleport</code>로 터미널에 가져오기</li><li><code>/desktop</code>으로 터미널 세션을 <a href="/claude-code-docs-ko/desktop.html">데스크톱 앱</a>에 전달하여 시각적 diff 리뷰</li><li>팀 채팅에서 작업 라우팅: <a href="/claude-code-docs-ko/slack.html">Slack</a>에서 <code>@Claude</code>를 멘션하여 버그 리포트를 보내면 풀 리퀘스트를 돌려받기</li></ul></details><h2 id="어디서든-claude-code-사용" tabindex="-1">어디서든 Claude Code 사용 <a class="header-anchor" href="#어디서든-claude-code-사용" aria-label="Permalink to &quot;어디서든 Claude Code 사용&quot;">​</a></h2><p>각 환경은 동일한 기본 Claude Code 엔진에 연결되므로, CLAUDE.md 파일, 설정, MCP 서버가 모든 환경에서 작동합니다.</p><p>위의 <a href="/claude-code-docs-ko/quickstart.html">Terminal</a>, <a href="/claude-code-docs-ko/vs-code.html">VS Code</a>, <a href="/claude-code-docs-ko/jetbrains.html">JetBrains</a>, <a href="/claude-code-docs-ko/desktop.html">Desktop</a>, <a href="/claude-code-docs-ko/claude-code-on-the-web.html">Web</a> 환경 외에도, Claude Code는 CI/CD, 채팅, 브라우저 워크플로우와 통합됩니다:</p><table tabindex="0"><thead><tr><th>하고 싶은 것</th><th>최적의 옵션</th></tr></thead><tbody><tr><td>휴대폰이나 다른 기기에서 로컬 세션 계속하기</td><td><a href="/claude-code-docs-ko/remote-control.html">Remote Control</a></td></tr><tr><td>Telegram, Discord, iMessage 또는 자체 웹훅의 이벤트를 세션에 푸시</td><td><a href="/claude-code-docs-ko/channels.html">Channels</a></td></tr><tr><td>로컬에서 작업을 시작하고 모바일에서 계속하기</td><td><a href="/claude-code-docs-ko/claude-code-on-the-web.html">Web</a> 또는 <a href="https://apps.apple.com/app/claude-by-anthropic/id6473753684" target="_blank" rel="noreferrer">Claude iOS 앱</a></td></tr><tr><td>반복 일정으로 Claude 실행</td><td><a href="/claude-code-docs-ko/web-scheduled-tasks.html">클라우드 예약 작업</a> 또는 <a href="/claude-code-docs-ko/desktop-scheduled-tasks.html">데스크톱 예약 작업</a></td></tr><tr><td>PR 리뷰 및 이슈 분류 자동화</td><td><a href="/claude-code-docs-ko/github-actions.html">GitHub Actions</a> 또는 <a href="/claude-code-docs-ko/gitlab-ci-cd.html">GitLab CI/CD</a></td></tr><tr><td>모든 PR에 대한 자동 코드 리뷰</td><td><a href="/claude-code-docs-ko/code-review.html">GitHub Code Review</a></td></tr><tr><td>Slack에서 버그 리포트를 풀 리퀘스트로 라우팅</td><td><a href="/claude-code-docs-ko/slack.html">Slack</a></td></tr><tr><td>라이브 웹 애플리케이션 디버그</td><td><a href="/claude-code-docs-ko/chrome.html">Chrome</a></td></tr><tr><td>자체 워크플로우를 위한 커스텀 에이전트 구축</td><td><a href="/claude-code-docs-ko/agent-sdk/overview.html">Agent SDK</a></td></tr></tbody></table><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>Claude Code를 설치한 후, 다음 가이드들이 더 깊이 이해하는 데 도움이 됩니다.</p><ul><li><a href="/claude-code-docs-ko/quickstart.html">빠른 시작</a>: 코드베이스 탐색부터 수정 커밋까지 첫 번째 실제 작업을 안내합니다</li><li><a href="/claude-code-docs-ko/memory.html">지침 및 메모리 저장</a>: CLAUDE.md 파일과 자동 메모리로 Claude에 지속적인 지침을 제공합니다</li><li><a href="/claude-code-docs-ko/common-workflows.html">일반 워크플로우</a> 및 <a href="/claude-code-docs-ko/best-practices.html">모범 사례</a>: Claude Code를 최대한 활용하기 위한 패턴</li><li><a href="/claude-code-docs-ko/settings.html">설정</a>: 워크플로우에 맞게 Claude Code를 커스터마이즈합니다</li><li><a href="/claude-code-docs-ko/troubleshooting.html">문제 해결</a>: 일반적인 문제에 대한 해결책</li><li><a href="https://code.claude.com/" target="_blank" rel="noreferrer">code.claude.com</a>: 데모, 가격, 제품 세부 정보</li></ul>`,68)])])}const k=a(i,[["render",d]]);export{u as __pageData,k as default};
